import{_ as r,o,c as s,a0 as d}from"./chunks/framework.DV6pVIgV.js";const p=JSON.parse('{"title":"定價與支援","description":"","frontmatter":{},"headers":[],"relativePath":"clf-c02/15.md","filePath":"clf-c02/15.md","lastUpdated":1783610848000}'),n={name:"clf-c02/15.md"};function e(a,t,g,l,i,h){return o(),s("div",null,[...t[0]||(t[0]=[d('<h1 id="定價與支援" tabindex="-1">定價與支援 <a class="header-anchor" href="#定價與支援" aria-label="Permalink to &quot;定價與支援&quot;">​</a></h1><p>AWS 計價原則、帳單工具、支援方案與成本最佳化。這章技術最少，重點在搞懂 AWS 怎麼收費、有哪些工具幫你管錢、支援方案怎麼選。</p><h2 id="aws-定價原則" tabindex="-1">AWS 定價原則 <a class="header-anchor" href="#aws-定價原則" aria-label="Permalink to &quot;AWS 定價原則&quot;">​</a></h2><p>AWS 的收費圍繞三個原則：</p><table tabindex="0"><thead><tr><th>原則</th><th>意思</th><th>對應服務</th></tr></thead><tbody><tr><td><strong>按用量付費（Pay-as-you-go）</strong></td><td>用多少付多少，不用先砸大錢、不用長期綁約</td><td>大多數服務的預設</td></tr><tr><td><strong>預留 / 承諾換折扣（Pay less when you reserve）</strong></td><td>事先承諾 1–3 年用量，單價大幅下降</td><td>Savings Plans、Reserved Instances</td></tr><tr><td><strong>用越多、單價越低（Volume discounts）</strong></td><td>用量越大，每單位越便宜（階梯式）</td><td>S3 等的階梯定價</td></tr></tbody></table><h3 id="aws-免費方案-free-tier-三種" tabindex="-1">AWS 免費方案（Free Tier）：三種 <a class="header-anchor" href="#aws-免費方案-free-tier-三種" aria-label="Permalink to &quot;AWS 免費方案（Free Tier）：三種&quot;">​</a></h3><p>Free Tier 分三類：</p><table tabindex="0"><thead><tr><th>類型</th><th>意思</th><th>例子</th></tr></thead><tbody><tr><td><strong>永久免費（Always Free）</strong></td><td>不會過期，永遠有一定免費額度</td><td>Lambda 每月 100 萬次請求、DynamoDB 25GB</td></tr><tr><td><strong>12 個月免費（12 Months Free）</strong>†</td><td>新帳號註冊後 12 個月內免費</td><td>EC2 t2.micro 每月 750 小時、S3 5GB</td></tr><tr><td><strong>短期試用（Trials）</strong></td><td>特定服務從啟用日起算的短期試用</td><td>某些服務的數十天試用</td></tr></tbody></table><blockquote><p>EC2 的免費額度是「<strong>12 個月</strong>」的，不是永久；Lambda / DynamoDB 那種小額度才是「<strong>永久免費</strong>」。</p></blockquote><blockquote><p>† 2025/7/15 起 Free Tier 制度異動（新帳號）：「12 個月免費」對 <strong>2025/7/15（含）之後建立的帳號已取消</strong>，改為額度制——註冊即得 $100，完成 5 項任務（EC2 / RDS / Lambda / Bedrock / Budgets 各 $20）可追加 $100，合計上限 $200。永久免費（Always Free）服務則不受影響。</p></blockquote><h3 id="三大成本來源" tabindex="-1">三大成本來源 <a class="header-anchor" href="#三大成本來源" aria-label="Permalink to &quot;三大成本來源&quot;">​</a></h3><p>帳單主要來自三件事：</p><ul><li><strong>運算（Compute）</strong>：跑 EC2 / Lambda 等的時間與規格，通常最大宗</li><li><strong>儲存（Storage）</strong>：存在 S3 / EBS 等的資料量</li><li><strong>資料傳輸（Data Transfer）</strong>： 傳入（IN）通常免費；傳出（OUT）到網際網路才收費——把資料「搬進」AWS 多半不用錢，「搬出去」才要錢</li></ul><h2 id="定價與帳單服務" tabindex="-1">定價與帳單服務 <a class="header-anchor" href="#定價與帳單服務" aria-label="Permalink to &quot;定價與帳單服務&quot;">​</a></h2><p>分清楚「哪個工具在哪個時間點用」：</p><table tabindex="0"><thead><tr><th>服務</th><th>在「什麼時間點」用</th><th>做什麼</th></tr></thead><tbody><tr><td><strong>AWS Pricing Calculator</strong></td><td><strong>建立之前</strong></td><td>估算「如果我這樣建，大概多少錢」</td></tr><tr><td><strong>AWS Billing Dashboard</strong></td><td>事後</td><td>查看與支付帳單</td></tr><tr><td><strong>AWS Cost Explorer</strong></td><td>事後</td><td><strong>視覺化、分析</strong>過去與現在的花費趨勢</td></tr><tr><td><strong>AWS Budgets</strong></td><td>持續</td><td>設<strong>預算門檻</strong>，接近 / 超過就<strong>發通知</strong></td></tr><tr><td><strong>Consolidated Billing</strong>（透過 Organizations）</td><td>持續</td><td>多帳號合併一張帳單，並合併用量享量大折扣</td></tr></tbody></table><blockquote><ul><li>「<strong>還沒建、想先估價</strong>」→ <strong>Pricing Calculator</strong></li><li>「分析<strong>過去 / 現在</strong>的花費、找趨勢」→ <strong>Cost Explorer</strong></li><li>「設<strong>門檻</strong>，快超支就<strong>通知我</strong>」→ <strong>Budgets</strong></li></ul><p>📌 <strong>Calculator 估未來、Cost Explorer 看過去、Budgets 守門檻。</strong></p></blockquote><h2 id="aws-支援方案-support-plans" tabindex="-1">AWS 支援方案（Support Plans） <a class="header-anchor" href="#aws-支援方案-support-plans" aria-label="Permalink to &quot;AWS 支援方案（Support Plans）&quot;">​</a></h2><blockquote><p><strong>重要時效提醒</strong>：AWS 支援方案<strong>正在改組</strong>。</p><ul><li><strong>現行五階</strong>（Basic / Developer / Business / Enterprise On-Ramp / Enterprise）持續供應<strong>到 2026/12/31</strong>。</li><li><strong>2027/1/1 起</strong>，Developer、Business、Enterprise On-Ramp 將終止；更新為 Basic / Business Support+ / Enterprise / Unified Operations。</li><li><strong>但目前的 CLF-C02 考試仍以「傳統五階」命題</strong>——考試請記下面的五階版本。</li></ul></blockquote><h3 id="傳統五階-考試版" tabindex="-1">傳統五階（考試版） <a class="header-anchor" href="#傳統五階-考試版" aria-label="Permalink to &quot;傳統五階（考試版）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方案</th><th>費用</th><th>商業關鍵問題回應時間</th><th>招牌特色</th></tr></thead><tbody><tr><td><strong>Basic</strong></td><td><strong>免費</strong></td><td>—</td><td>帳號 / 帳單支援、文件、有限 Trusted Advisor、Health Dashboard</td></tr><tr><td><strong>Developer</strong></td><td>付費（低）</td><td>一般 &lt; 24h（上班時間 email）</td><td>入門 / 測試用，問 Cloud Support Associate</td></tr><tr><td><strong>Business</strong></td><td>付費</td><td>生產系統受損 &lt; 4h、停擺 &lt; 1h（24/7 電話 / chat）</td><td><strong>完整 Trusted Advisor</strong>、24/7 技術支援、Support API</td></tr><tr><td><strong>Enterprise On-Ramp</strong></td><td>付費</td><td>商業關鍵 <strong>&lt; 30 min</strong></td><td><strong>TAM 池</strong>（一群 TAM）、成本優化工作坊</td></tr><tr><td><strong>Enterprise</strong></td><td>付費（高）</td><td>商業關鍵 <strong>&lt; 15 min</strong></td><td><strong>專屬 TAM</strong>、Concierge 帳務協助、Well-Architected review</td></tr></tbody></table><blockquote><p>「需要一位<strong>專屬 TAM</strong>（designated Technical Account Manager）」→ Enterprise（On-Ramp 只有「TAM 池」，不是專屬）</p><p>24/7 電話 / chat 支援 + 完整 Trusted Advisor → Business 以上才有</p></blockquote><h2 id="aws-marketplace-與合作夥伴" tabindex="-1">AWS Marketplace 與合作夥伴 <a class="header-anchor" href="#aws-marketplace-與合作夥伴" aria-label="Permalink to &quot;AWS Marketplace 與合作夥伴&quot;">​</a></h2><table tabindex="0"><thead><tr><th>資源</th><th>是什麼</th></tr></thead><tbody><tr><td><strong>AWS Marketplace</strong></td><td>數位軟體商店：找、買、快速部署<strong>第三方軟體</strong>到你的 AWS 環境（如現成的防火牆、資料庫映像）</td></tr><tr><td><strong>AWS Partner Network（APN）</strong></td><td>AWS 的<strong>合作夥伴</strong>生態系：<strong>諮詢夥伴</strong>（幫你規劃 / 建置 / 遷移）與<strong>技術夥伴</strong>（提供軟體 / 工具）</td></tr></tbody></table><blockquote><p>「快速取得 / 部署<strong>第三方商業軟體</strong>」→ <strong>AWS Marketplace</strong></p><p>「需要<strong>外部顧問</strong>幫忙上雲」→ <strong>AWS Partner Network</strong>。</p></blockquote><h2 id="成本最佳化實務" tabindex="-1">成本最佳化實務 <a class="header-anchor" href="#成本最佳化實務" aria-label="Permalink to &quot;成本最佳化實務&quot;">​</a></h2><ul><li><strong>選對計費模式</strong>：穩定負載用 Savings Plans / Reserved；可中斷工作用 Spot；短期不確定用 On-Demand</li><li><strong>Right-sizing</strong>：用 CloudWatch 指標檢視使用率，別開過大的機器</li><li><strong>刪閒置資源</strong>：沒在用的 EC2、沒掛載的 EBS、沒關聯的 Elastic IP → 用 Trusted Advisor 成本最佳化揪出來</li><li><strong>儲存分層</strong>：S3 生命週期政策自動把冷資料移到便宜類別</li><li><strong>彈性擴展</strong>：Auto Scaling 隨需求增減，不用照尖峰常備</li><li><strong>合併帳單</strong>：Consolidated Billing 集中用量達量大折扣門檻</li></ul><h2 id="考試重點整理" tabindex="-1">考試重點整理 <a class="header-anchor" href="#考試重點整理" aria-label="Permalink to &quot;考試重點整理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境需求</th><th>答案</th></tr></thead><tbody><tr><td>把資料搬「進」AWS 的費用</td><td>通常<strong>免費</strong></td></tr><tr><td>EC2 t2.micro 的免費額度</td><td><strong>12 個月免費</strong>（非永久）</td></tr><tr><td>Lambda / DynamoDB 的小額免費額度</td><td><strong>永久免費（Always Free）</strong></td></tr><tr><td>還沒建，先估算成本</td><td><strong>Pricing Calculator</strong></td></tr><tr><td>分析過去 / 現在花費趨勢</td><td><strong>Cost Explorer</strong></td></tr><tr><td>設預算門檻、快超支就通知</td><td><strong>AWS Budgets</strong></td></tr><tr><td>多帳號一張帳單 + 量大折扣</td><td><strong>Consolidated Billing</strong>（Organizations）</td></tr><tr><td>需要一位「專屬 TAM」</td><td><strong>Enterprise</strong> 支援方案</td></tr><tr><td>只需帳單 / 帳號協助、免費</td><td><strong>Basic</strong> 支援方案</td></tr><tr><td>需要 24/7 技術支援 + 完整 Trusted Advisor</td><td><strong>Business</strong>（含）以上</td></tr><tr><td>取得 / 部署第三方商業軟體</td><td><strong>AWS Marketplace</strong></td></tr><tr><td>找顧問幫忙上雲</td><td><strong>AWS Partner Network</strong></td></tr></tbody></table>',29)])])}const u=r(n,[["render",e]]);export{p as __pageData,u as default};
